var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"죽인다……. 다음에 잡으면 반드시 죽인다…….","JPN":"殺す……次に会う時必ず殺してやる……","ENG":"She's dead... She's a dead woman the next time I see her...","TWN":"我要殺了你……下次被我逮到絕對要殺了你……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우……. 나 왔어.","JPN":"ふう……ただいま。","ENG":"*Sigh* I'm back.","TWN":"哀……我來了。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"왔어요, 사장님? 의뢰비는요?","JPN":"おかえりなさい、社長。報酬はちゃんともらってきました？","ENG":"Welcome back, Boss. Where's our money?","TWN":"老闆你來啦，這次的委託費呢？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……뭐지? 데자뷔인가?","JPN":"……なんだ？　デジャブか？","ENG":"Huh? I think I'm having a déjà vu.","TWN":"……這是什麼既視感？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……그럼, 의뢰인이 다시 쫓아오지는 않았어요?","JPN":"……で、また依頼主が追いかけてきたりしませんでしたか？","ENG":"... Then, didn't the client come back for you?","TWN":"……是喔，那委託人沒有追上來嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다행히 아직은 잠잠해.","JPN":"幸いまだ動きはない。","ENG":"Not yet, fortunately.","TWN":"好險目前都還沒什麼動作！"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 아무리 날뛰어도 리플레이서 잔당들보다는 낫겠지.","JPN":"まあ、いくら暴れてもリプレイサーの残党よりはマシだろう。","ENG":"Well, even if he does, he can't be worse than the Replacer remnants.","TWN":"不過再怎麼樣，他們還是比克隆集團的傢伙好對付啦～"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"의뢰비도 못 받고, 침식체 상대한다고 특수탄도 엄청 쓰셨지만요.","JPN":"依頼費ももらえず、侵食体用の時殊弾もたっぷり使ったようですが。","ENG":"But he didn't pay you. And you spent a lot of special bullets on his C.O., too.","TWN":"只是你錢沒收到，然後為了對付侵蝕體又用掉很多特殊彈。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크흠. 그나마 제인이 마스코트 인형 안에 돈을 좀 넣어 뒀더군.","JPN":"まあでも、ジェーンがマスコットのぬいぐるみの中にお金を少し入れていたみたいだ。","ENG":"Kahem. But Jane left some money inside that mascot doll.","TWN":"咳咳，這次至少珍妮有在娃娃裡面塞一些錢。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"분하지만 이걸로 일단 헴스워스 영감님에게 줄 외상값은 틀어막아야지.","JPN":"悔しいが、とりあえずヘムズワース爺に返す代金は何とかなりそうだ。","ENG":"I'm still angry with her, but I can use the money to pay Helmsworth.","TWN":"雖然很生氣，不過起碼可以先把欠漢姆沃斯的錢還掉吧？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"이번달치 외상을 갚으면 어떻게 되는지 아세요?","JPN":"今月分の返済が終わるとどうなるか知っていますか？","ENG":"Do you know what happens if you pay him this month?","TWN":"這個月的還完後，你知道會怎樣嗎？"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……다음달치 외상을 갚아야겠지.","JPN":"……来月分の返済が始まる。","ENG":"... I'll have made one more payment on what I owe?","TWN":"……就是要還下個月的。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"그것만이면 다행이게요. 공과금도 못 낸 지 한참 됐다고요.","JPN":"それだけならまだマシです。光熱費も未払いのまま結構経っていますよ。","ENG":"His money isn't the only problem. There are other bills we haven't paid. For months.","TWN":"那還只是小事，稅金都多久沒繳了。"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"돈 얘기는 나중에 해 줘. 지금은 그냥…….","JPN":"お金の話は後にしてくれ。今はただ……","ENG":"Can we talk about money later? For now, I want to—","TWN":"先不要跟我談錢的事，我要先……"},"stage":{"bg":"DATABASE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"응? 갑자기 왜 불이 꺼져? 정전인가?","JPN":"うん？　急になんだ？　停電か？","ENG":"Erm, the lights went out all of a sudden. Are we having a power outage?","TWN":"嗯？怎麼突然變暗？是停電嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"전기가 끊긴 걸 거예요. 경고장 몇 번 왔거든요.","JPN":"電気を止められたのでしょう。督促状が何回も届いていましたよ。","ENG":"The power company probably cut off our electricity. We've gotten the final notice several times.","TWN":"是被斷電啦！都收到好幾張停電通知了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……왜 목숨 걸고 일할수록 내 재정 상황은 더 파탄 나는 거지?","JPN":"……なぜ命がけで働くほど、俺の経済状況はどんどん破綻していくのだろう?","ENG":"How come I'm struggling more the harder I work?","TWN":"……為什麼我越是拼命幹活兒，我的財務狀況就越悽慘？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"투덜거릴 시간 있으면 성냥이라도 좀 찾아봐요.","JPN":"文句を言う暇があるなら、ロウソクでも探してください。","ENG":"If you have time to complain, you have time to find some matchsticks.","TWN":"有時間在那邊廢話，不如去快點去找火柴啦！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"어두운 데서 어디 부딪쳤다가 몸에 생채기라도 나면 어떡해요.","JPN":"暗い中どこかにぶつかって私がケガでもしたら、どうしてくれるんですか。","ENG":"I don't want you to bump into things and bruise yourself in the dark.","TWN":"這麼暗，要是撞傷我的身體怎麼辦！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"응? 갑자기 뭘 그렇게 뒤적거리세요?","JPN":"うん？　何を漁ってるんです？","ENG":"Mm? What are you looking for all of a sudden?","TWN":"嗯？你在找什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조금만 기다려 봐. 분명히 그 때 받아다가…….","JPN":"ちょっと待ってくれ。確かあの時にもらったものが……","ENG":"Give me a moment. I had it here somewhere...","TWN":"等我一下，我記得那時候收在……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 여기 있었군.","JPN":"ああ、ここにあった。","ENG":"Ah, there it is.","TWN":"找到了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하아, 됐어. 지금은 이걸로 때우자고.","JPN":"よし、できた。今はこれで済ますしかない。","ENG":"Whew, okay. We can use this for now.","TWN":"哈哈！OK！就用這個先頂著吧！"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"무드등이네요? 우리 사무소에 이런 로맨틱한 물건이 있었어요?","JPN":"ムードランプ？　うちの事務所にこんなロマンチックな物があったんですか？","ENG":"A mood light? I didn't know we had something so romantic in the office.","TWN":"小夜燈？我們事務所有這麼浪漫的東西喔？"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 예전에 어떤 할머니 의뢰를 해 주고 돈 대신 받은 거야.","JPN":"ああ。以前あるおばあさんから依頼を受けて、代金の代わりにもらったものだ。","ENG":"Yeah, I got it in return for a favor I did for an old lady before.","TWN":"嗯嗯，這是之前我替一個老奶奶完成委託後，她就給我這個代替委託費。"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"네에. 그러셨겠죠. 돈으로 받았으면 전기는 안 끊겼겠네요.","JPN":"はい、そうでしょうね。お金をもらっていたら、電気を止められることはなかったでしょうね。","ENG":"Yeah, well, you should have gotten money to keep the lights on.","TWN":"哦～果然是老闆會幹的事，要是收的是錢，我們現在也不會被斷電呢～"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"빈정거리지 마. 덕분에 지금 유용하게 잘 쓰고 있잖아.","JPN":"嫌味を言うな。少なくとも今は助かっているじゃないか。","ENG":"Stop complaining. At least it's handy now.","TWN":"你別這樣挖苦我，這東西現在也派上用場啦！"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나저나 앞으로가 문제군. 정말 제인이 숨은 곳이라도 쫓아가야 하나…….","JPN":"しかしこれからが問題だな。本気出してジェーンを探さなければならないのか……","ENG":"By the way, what do I do from now on? Do I really have to go after Jane?","TWN":"問題是以後該怎麼辦，難道我要找到珍妮躲藏的地方嗎……"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"아, 그 건 말인데요. 사장님 나가 있는 동안 그 워커 대령이란 사람이…….","JPN":"あ、それなんですけど。社長が出ている間にウォーカー大佐という方が……","ENG":"Ah, about that. While you were away, this guy, Colonel Walker...","TWN":"說到這個！老闆不在的時候，有位叫沃克上校的人……"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"사장님? 듣고 있어요?","JPN":"社長？　聞いてます？","ENG":"John? Are you listening?","TWN":"老闆？你有在聽嗎？"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……뭐 이리 금방 잠들어. 한창 클 나이도 아니면서.","JPN":"……寝落ちしたのね。育ち盛りの子どもでもないのにすぐ寝ちゃって。","ENG":"How come he fell asleep so quickly? He's not a teenager.","TWN":"……這麼快就睡著啦？又還沒到七老八十的年紀…"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"어휴, 이 화상. 감기라도 걸리면 어쩌려고.","JPN":"お腹丸出しじゃない。風邪でもひいたらどうするつもりなの。","ENG":"Tsk, tsk. This fool, sleeping without a blanket on.","TWN":"真是的，睡在這裡萬一感冒怎麼辦？"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"의뢰주한테 일 얘기 하려면 시간 좀 걸린다고 말해 둬야겠네.","JPN":"依頼主に、仕事の話をするには少し時間がかかると伝えておかないとね。","ENG":"I'd better tell the client he'll have to wait to talk about the job.","TWN":"必須先跟委託人說一聲，要談工作的事會需要花一點時間。"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"지금은 일단 푹 주무세요, 사장님.","JPN":"とりあえず今はゆっくり休んでくださいね、社長。","ENG":"For now, sleep tight, Boss.","TWN":"現在你就好好睡一覺吧，老闆。"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"……담요 빌려드린 값은 나중에 받을 테니까.","JPN":"……貸した毛布代は今度きっちりもらいますから。","ENG":"... I'll charge you for the blanket later.","TWN":"……毯子的錢我以後再跟你收！"},"stage":{"bg":"SOF_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};